import React, { useCallback, useState } from 'react';
import { Button, FormControl, TextField } from '@material-ui/core';
import PropTypes from 'prop-types';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { SUCCESS_MESSAGE_TYPE } from '../utils/constants';
import { setSnackbarMessage } from '../utils/gatsby-frontend-helpers';

const SHORT_ANSWER_TYPE = 0;
const LONG_ANSWER_TYPE = 1;

const useStyles = makeStyles((theme) => ({
    submitButton: {
        marginTop: '20px',
    },
}));

function ContactForm({
    googleFormId,
    googleFormData,
    className = null,
}) {
    const intl = useIntl();
    const [isFormSubmitted, setIsFormSubmitted] = useState(false);
    const { loadData, shuffleSeed } = googleFormData;
    const classes = useStyles();

    const formBody = loadData[1][1].map((data) => {
        const formName = data[1];
        const formType = data[3];
        const formCode = data[4][0][0];
        const extraProps = {
            style: { margin: '5px 0' },
            fullWidth: true,
            label: intl.formatMessage({ id: formName }),
        };

        if (formType === LONG_ANSWER_TYPE) {
            return (
                <TextField
                    // eslint-disable-next-line react/jsx-props-no-spreading
                    {...extraProps}
                    key={formCode}
                    name={`entry.${formCode}`}
                    type={formName}
                    multiline
                    required
                    rows={6}
                    rowsMax={6}
                    inputProps={{ maxLength: 1000 }}
                />
            );
        }

        // if (formType === SHORT_ANSWER_TYPE)
        return (
            <TextField
                // eslint-disable-next-line react/jsx-props-no-spreading
                {...extraProps}
                key={formCode}
                name={`entry.${formCode}`}
                type={formName}
                required
            />
        );
    });

    const onIframeLoad = useCallback((a, b, c, d) => {
        // https://stackoverflow.com/a/8558731
        if (isFormSubmitted) {
            setSnackbarMessage('your_message_submitted', SUCCESS_MESSAGE_TYPE);
            window.location = window.location.href;
        }
    }, [isFormSubmitted]);

    const onFormSubmit = useCallback((e) => {
        setIsFormSubmitted(true);
    }, [setIsFormSubmitted]);

    return (
        <FormControl
            className={className}
        >
            <iframe
                title="hidden_iframe"
                name="hidden_iframe"
                id="hidden_iframe"
                style={{ display: 'none' }}
                onLoad={onIframeLoad}
            />
            <form
                action={`https://docs.google.com/forms/d/e/${googleFormId}/formResponse`}
                method="post"
                onSubmit={onFormSubmit}
                target="hidden_iframe"
            >
                {formBody}
                <Button
                    className={classes.submitButton}
                    variant="contained"
                    color="default"
                    type="submit"
                >
                    {intl.formatMessage({ id: 'send_message' })}
                </Button>
            </form>
        </FormControl>
    );
}

ContactForm.propTypes = {
    googleFormId: PropTypes.string.isRequired,
    googleFormData: PropTypes.object.isRequired,
    className: PropTypes.string,
};

export default ContactForm;
