import React, { useMemo } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';
import { graphql } from 'gatsby';

// Utils
import { contactData } from '../utils/config';
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import ContactForm from '../components/ContactForm';

const useStyles = makeStyles((theme) => ({
    contactWrapper: {
        padding: '15px 0',
    },
    contactForm: {
        margin: '0 0 20px',
    },
}));

const Contact = ({ data, pageContext, location }) => {
    const intl = useIntl();
    const classes = useStyles();
    const {
        googleFormData,
    } = pageContext;
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'contact' })}
                keywords={[
                    intl.formatMessage({ id: 'contact' }),
                    intl.formatMessage({ id: 'seo_keywords.personal_blog' }),
                    intl.formatMessage({ id: 'seo_keywords.personal_projects' }),
                    intl.formatMessage({ id: 'seo_keywords.travels' }),
                    intl.formatMessage({ id: 'seo_keywords.developer' }),
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <div className={classes.contactWrapper}>
                <Typography
                    className={classes.cookiePolicyText}
                    color="textPrimary"
                    variant="h4"
                >
                    {intl.formatMessage({ id: 'contact' })}
                </Typography>
                <ContactForm
                    className={classes.contactForm}
                    googleFormId={contactData.googleFormId}
                    googleFormData={googleFormData}
                />
            </div>
        </Layout>
    );
};

export default Contact;

export const pageQuery = graphql`
    query {
        site {
            siteMetadata {
                siteUrl
            }
        }
    }
`;
